// Below is the updated content of DMAC/RTL/DMAC_CFG.sv

module DMAC_CFG
(
    input wire clk,
    input wire rst_n, // _n means active low
    // AMBA APB interface
    input wire psel_i,
    input wire penable_i,
    input wire [11:0] paddr_i,
    input wire pwrite_i,
    input wire [31:0] pwdata_i,
    output reg pready_o,
    output reg [31:0] prdata_o,
    output reg pslverr_o,
    // configuration registers
    output reg [31:0] src_addr_o,
    output reg [31:0] dst_addr_o,
    output reg [15:0] byte_len_o,
    output wire start_o,
    input wire done_i
);

    // Configuration register to read/write
    reg [31:0] src_addr;
    reg [31:0] dst_addr;
    reg [15:0] byte_len;

    //----------------------------------------------------------
    // Write
    //----------------------------------------------------------
    wire wren;
    assign wren = psel_i & penable_i & pwrite_i;

    always @(posedge clk) begin
        if (!rst_n) begin
            src_addr <= 32'b0;
            dst_addr <= 32'b0;
            byte_len <= 16'b0;
        end
        else if (wren) begin
            case (paddr_i)
                `SRC_ADDR: src_addr <= pwdata_i;
                `DST_ADDR: dst_addr <= pwdata_i;
                `LEN_ADDR: byte_len <= pwdata_i[15:0];
            endcase
        end
    end

    wire start;
    assign start = (paddr_i == `START_ADDR) && wren && (pwdata_i == 32'b1);

    //----------------------------------------------------------
    // READ
    //----------------------------------------------------------
    reg [31:0] rdata;

    always @(posedge clk) begin
        if (!rst_n) begin
            rdata <= 32'b0;
        end
        else if (psel_i & !penable_i & !pwrite_i) begin
            case (paddr_i)
                `SRC_ADDR: rdata <= src_addr;
                `DST_ADDR: rdata <= dst_addr;
                `LEN_ADDR: rdata <= {16'b0, byte_len};
                // Assuming `STAT_ADDR` gives status of `done_i`
                `STAT_ADDR: rdata <= {31'b0, done_i};
                default: rdata <= 32'b0;
            endcase
        end
    end

    // output assignments
    assign pready_o = 1'b1;
    assign prdata_o = rdata;
    assign pslverr_o = 1'b0;
    assign src_addr_o = src_addr;
    assign dst_addr_o = dst_addr;
    assign byte_len_o = byte_len;
    assign start_o = start;
endmodule

// End DMAC/RTL/DMAC_CFG.sv
```

