    output reg [15:0] byte_len_o,
    output wire start_o,
    input wire done_i
);

    // Configuration register to read/write
    reg [31:0] src_addr;
    reg [31:0] dst_addr;
    reg [15:0] byte_len;
    reg start_reg;

    //----------------------------------------------------------
    // Write
    //----------------------------------------------------------
    wire wren;
    assign wren = psel_i & penable_i & pwrite_i;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            src_addr <= 32'b0;
            dst_addr <= 32'b0;
            byte_len <= 16'b0;
            start_reg <= 1'b0;
        end
        else if (wren) begin
            case (paddr_i)
                12'h100: src_addr <= pwdata_i;
                12'h104: dst_addr <= pwdata_i;
                12'h108: byte_len <= pwdata_i[15:0];
                12'h10C: start_reg <= pwdata_i[0]; // Assuming pwdata_i[0] is the start bit
                default: ;
            endcase
        end
    end

    wire start;
    assign start = start_reg & wren & (paddr_i == 12'h10C);

    //----------------------------------------------------------
    // READ
    //----------------------------------------------------------
    reg [31:0] rdata;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rdata <= 32'b0;
        end
        else if (psel_i & !penable_i & !pwrite_i) begin
            case (paddr_i)
                12'h100: rdata <= src_addr;
                12'h104: rdata <= dst_addr;
                12'h108: rdata <= {16'b0, byte_len};
                12'h110: rdata <= {31'b0, done_i}; // Assuming done_i is directly mapped to DMA_STATUS
                default: rdata <= 32'b0;
