```verilog
module DMAC_CFG
(
    input wire clk,
    input wire rst_n, // _n means active low
    // AMBA APB interface
    input wire psel_i,
    input wire penable_i,
    input wire [11:0] paddr_i,
    input wire pwrite_i,
    input wire [31:0] pwdata_i,
    output reg pready_o,
    output reg [31:0] prdata_o,
    output reg pslverr_o,
    // configuration registers
    output reg [31:0] src_addr_o,
    output reg [31:0] dst_addr_o,
    output reg [15:0] byte_len_o,
    output wire start_o,
    input wire done_i
);

    // Configuration register to read/write
    reg [31:0] src_addr;
    reg [31:0] dst_addr;
    reg [15:0] byte_len;
    reg [31:0] dma_ver = 32'h0001_2024; // DMA version register initialized as per specification

    //----------------------------------------------------------
    // Write
    //----------------------------------------------------------
    wire wren;
    assign wren = psel_i & penable_i & pwrite_i;

    always @(posedge clk) begin
        if (!rst_n) begin
            src_addr <= 32'b0;
            dst_addr <= 32'b0;
            byte_len <= 16'b0;
        end
        else if (wren) begin
            case (paddr_i)
                12'h100: src_addr <= pwdata_i;
                12'h104: dst_addr <= pwdata_i;
                12'h108: byte_len <= pwdata_i[15:0];
                // No write case for DMA_VER as it is read-only
                // No write case for DMA_CMD as it is handled separately
            endcase
        end
    end

    wire start;
    assign start = (paddr_i == 12'h10C) && wren && (pwdata_i[0] == 1'b1);

    //----------------------------------------------------------
    // READ
    //----------------------------------------------------------
    reg [31:0] rdata;

    always @(posedge clk) begin
        if (!rst_n) begin
            rdata <= 32'b0;
        end
        else if (psel_i & !penable_i & !pwrite_i) begin
            case (paddr_i)
                12'h000: rdata <= dma_ver;
                12'h100: rdata <= src_addr;
                12'h104: rdata <= dst_addr;
                12'h108: rdata <= {16'b0, byte_len};
                12'h110: rdata <= {31'b0, done_i}; // Assuming done_i directly maps to DMA_STATUS
                default: rdata <= 32'b0;
            endcase
        end
    end

    // output assignments
    assign pready_o = 1'b1;
    assign prdata_o = rdata;
    assign pslverr_o = 1'b0;
    assign src_addr_o = src_addr;
    assign dst_addr_o = dst_addr;
    assign byte_len_o = byte_len;
    assign start_o = start;
endmodule
```

This code update includes the handling for the DMA version register (`DMA_VER`) as specified, which is set to a fixed value representing the major version and the release year. The write operations to the source address (`DMA_SRC`), destination address (`DMA_DST`), and byte length (`DMA_LEN`) registers are implemented as per the specification. The start command (`DMA_CMD`) is handled by checking if the write operation is targeted at the `DMA_CMD` register and if the written value is `1`. The read operations return the value of the requested register, including the DMA version when the `DMA_VER` register is read.

